//
// Hand-authored Scrape.do governor + SERP-history schema and methods. Lives in
// a separate file from store.go so the generator's hand-edit-durability rule
// preserves it across regenerations (no "Generated by ... DO NOT EDIT" header).
//
// This is the storage layer behind the CLI's three differentiators:
//   - a cross-process concurrency LEASE (concurrency_leases) so multiple agent
//     processes on one machine never exceed the plan's ConcurrentRequest cap,
//   - a local credit LEDGER (credit_ledger + scrape_jobs) debited from the
//     authoritative `Scrape.do-Request-Cost` response header, and
//   - SERP SNAPSHOTS (serp_snapshots + serp_organic) so `drift`/`movers` can
//     diff rank changes offline with no re-spend.
//
// EnsureScrapedoSchema is called lazily by every command that touches these
// tables, so the schema appears on first use even on an install that never ran
// `sync`.

package store

import (
	"context"
	"database/sql"
	"fmt"
	"time"
)

// ScrapeExtras wraps the shared *sql.DB with the Scrape.do governor methods.
// Construct via NewScrapeExtras(store.DB()).
type ScrapeExtras struct{ db *sql.DB }

// NewScrapeExtras returns a governor-store wrapper over an open *sql.DB.
func NewScrapeExtras(db *sql.DB) *ScrapeExtras { return &ScrapeExtras{db: db} }

const scrapedoSchema = `
CREATE TABLE IF NOT EXISTS scrape_jobs (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    kind TEXT NOT NULL,
    target TEXT NOT NULL,
    mode TEXT NOT NULL,
    agent TEXT,
    http_status INTEGER,
    cost INTEGER NOT NULL DEFAULT 0,
    cost_source TEXT,
    remaining_credits INTEGER,
    bytes INTEGER,
    ok INTEGER NOT NULL DEFAULT 0,
    error TEXT,
    created_at TEXT NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_scrape_jobs_created ON scrape_jobs(created_at);

CREATE TABLE IF NOT EXISTS credit_ledger (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    job_id INTEGER,
    mode TEXT NOT NULL,
    agent TEXT,
    family TEXT,
    cost INTEGER NOT NULL,
    cost_source TEXT NOT NULL,
    created_at TEXT NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_ledger_created ON credit_ledger(created_at);

CREATE TABLE IF NOT EXISTS usage_snapshots (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    is_active INTEGER,
    concurrent_request INTEGER,
    remaining_concurrent INTEGER,
    max_monthly INTEGER,
    remaining_monthly INTEGER,
    captured_at TEXT NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_usage_captured ON usage_snapshots(captured_at);

CREATE TABLE IF NOT EXISTS concurrency_leases (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    agent TEXT,
    acquired_at TEXT NOT NULL,
    heartbeat_at TEXT NOT NULL
);

CREATE TABLE IF NOT EXISTS serp_snapshots (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    param_hash TEXT NOT NULL,
    query TEXT NOT NULL,
    gl TEXT,
    hl TEXT,
    google_domain TEXT,
    device TEXT,
    organic_count INTEGER,
    raw TEXT,
    fetched_at TEXT NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_serp_snap_hash ON serp_snapshots(param_hash, fetched_at);

CREATE TABLE IF NOT EXISTS serp_organic (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    snapshot_id INTEGER NOT NULL,
    param_hash TEXT NOT NULL,
    position INTEGER,
    title TEXT,
    link TEXT,
    domain TEXT,
    snippet TEXT,
    fetched_at TEXT NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_serp_org_snap ON serp_organic(snapshot_id);
CREATE INDEX IF NOT EXISTS idx_serp_org_hash ON serp_organic(param_hash, fetched_at);

CREATE TABLE IF NOT EXISTS cost_budget (
    id INTEGER PRIMARY KEY CHECK (id = 1),
    max_credits INTEGER,
    max_monthly_pct REAL,
    updated_at TEXT NOT NULL
);
`

// EnsureScrapedoSchema creates the governor + SERP-history tables if absent.
// Safe to call repeatedly and concurrently (all statements are IF NOT EXISTS).
func (x *ScrapeExtras) EnsureScrapedoSchema(ctx context.Context) error {
	if _, err := x.db.ExecContext(ctx, scrapedoSchema); err != nil {
		return fmt.Errorf("ensure scrape-do schema: %w", err)
	}
	return nil
}

// ---- Concurrency lease (cross-process) ----------------------------------

// LeaseTTL is how long a lease may live without a release before it is
// considered abandoned (a crashed agent process). Single billed calls finish
// well within this; batch holds and releases per item.
const LeaseTTL = 90 * time.Second

// AcquireLease atomically reclaims stale leases, counts the live ones, and — if
// fewer than cap are held — inserts a new lease. Returns (leaseID, acquired,
// activeAfter). When acquired is false the caller is at the concurrency ceiling
// and should back off and retry. cap <= 0 disables the ceiling (always grants).
func (x *ScrapeExtras) AcquireLease(ctx context.Context, agent string, cap int, now time.Time) (int64, bool, int, error) {
	tx, err := x.db.BeginTx(ctx, nil)
	if err != nil {
		return 0, false, 0, err
	}
	defer func() { _ = tx.Rollback() }()

	// The DELETE runs first and is a write, so it takes SQLite's RESERVED
	// (write) lock immediately — even when it removes zero rows. With WAL +
	// busy_timeout serializing writers, no other process can be between its
	// own DELETE and INSERT while we hold it, so the COUNT→cap-check→INSERT
	// below is atomic across processes and the cap cannot be over-granted.
	cutoff := now.Add(-LeaseTTL).UTC().Format(time.RFC3339Nano)
	if _, err := tx.ExecContext(ctx, `DELETE FROM concurrency_leases WHERE heartbeat_at < ?`, cutoff); err != nil {
		return 0, false, 0, err
	}
	var active int
	if err := tx.QueryRowContext(ctx, `SELECT COUNT(*) FROM concurrency_leases`).Scan(&active); err != nil {
		return 0, false, 0, err
	}
	if cap > 0 && active >= cap {
		if err := tx.Commit(); err != nil {
			return 0, false, active, err
		}
		return 0, false, active, nil
	}
	ts := now.UTC().Format(time.RFC3339Nano)
	res, err := tx.ExecContext(ctx, `INSERT INTO concurrency_leases (agent, acquired_at, heartbeat_at) VALUES (?, ?, ?)`, agent, ts, ts)
	if err != nil {
		return 0, false, active, err
	}
	id, _ := res.LastInsertId()
	if err := tx.Commit(); err != nil {
		return 0, false, active, err
	}
	return id, true, active + 1, nil
}

// ReleaseLease removes a held lease. Best-effort; never errors fatally.
func (x *ScrapeExtras) ReleaseLease(ctx context.Context, id int64) error {
	if id == 0 {
		return nil
	}
	_, err := x.db.ExecContext(ctx, `DELETE FROM concurrency_leases WHERE id = ?`, id)
	return err
}

// ActiveLeases returns the count of currently-held (non-stale) leases.
func (x *ScrapeExtras) ActiveLeases(ctx context.Context, now time.Time) (int, error) {
	cutoff := now.Add(-LeaseTTL).UTC().Format(time.RFC3339Nano)
	var n int
	err := x.db.QueryRowContext(ctx, `SELECT COUNT(*) FROM concurrency_leases WHERE heartbeat_at >= ?`, cutoff).Scan(&n)
	return n, err
}

// ---- Credit ledger + job log -------------------------------------------

// CallRecord is one billed (or attempted) API call to record.
type CallRecord struct {
	Kind             string
	Target           string
	Mode             string
	Agent            string
	Family           string
	HTTPStatus       int
	Cost             int
	CostSource       string // "header" | "estimate"
	RemainingCredits int    // -1 if unknown
	Bytes            int
	OK               bool
	Err              string
	At               time.Time
}

// RecordCall inserts a scrape_jobs row and, when the call was billed (cost > 0),
// a matching credit_ledger debit. Both happen in one transaction so the ledger
// never drifts from the job log.
func (x *ScrapeExtras) RecordCall(ctx context.Context, r CallRecord) error {
	tx, err := x.db.BeginTx(ctx, nil)
	if err != nil {
		return err
	}
	defer func() { _ = tx.Rollback() }()
	ts := r.At.UTC().Format(time.RFC3339)
	var rem any
	if r.RemainingCredits >= 0 {
		rem = r.RemainingCredits
	}
	res, err := tx.ExecContext(ctx, `INSERT INTO scrape_jobs
        (kind, target, mode, agent, http_status, cost, cost_source, remaining_credits, bytes, ok, error, created_at)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?)`,
		r.Kind, r.Target, r.Mode, nullStr(r.Agent), r.HTTPStatus, r.Cost, r.CostSource, rem, r.Bytes, boolInt(r.OK), nullStr(r.Err), ts)
	if err != nil {
		return err
	}
	if r.Cost > 0 {
		jobID, _ := res.LastInsertId()
		if _, err := tx.ExecContext(ctx, `INSERT INTO credit_ledger
            (job_id, mode, agent, family, cost, cost_source, created_at)
            VALUES (?,?,?,?,?,?,?)`,
			jobID, r.Mode, nullStr(r.Agent), nullStr(r.Family), r.Cost, r.CostSource, ts); err != nil {
			return err
		}
	}
	return tx.Commit()
}

// SpendSummary is the rolled-up ledger spend since a cutoff.
type SpendSummary struct {
	TotalCredits int            `json:"total_credits"`
	Calls        int            `json:"calls"`
	ByMode       map[string]int `json:"by_mode,omitempty"`
	ByAgent      map[string]int `json:"by_agent,omitempty"`
}

// Spend totals ledger credits since `since`, broken down by mode and agent.
func (x *ScrapeExtras) Spend(ctx context.Context, since time.Time) (SpendSummary, error) {
	out := SpendSummary{ByMode: map[string]int{}, ByAgent: map[string]int{}}
	cutoff := since.UTC().Format(time.RFC3339)
	if err := x.db.QueryRowContext(ctx,
		`SELECT COALESCE(SUM(cost),0), COUNT(*) FROM credit_ledger WHERE created_at >= ?`, cutoff).
		Scan(&out.TotalCredits, &out.Calls); err != nil {
		return out, err
	}
	if err := scanKV(ctx, x.db, `SELECT mode, COALESCE(SUM(cost),0) FROM credit_ledger WHERE created_at >= ? GROUP BY mode ORDER BY 2 DESC`, cutoff, out.ByMode); err != nil {
		return out, err
	}
	if err := scanKV(ctx, x.db, `SELECT COALESCE(agent,'(unattributed)'), COALESCE(SUM(cost),0) FROM credit_ledger WHERE created_at >= ? GROUP BY agent ORDER BY 2 DESC`, cutoff, out.ByAgent); err != nil {
		return out, err
	}
	return out, nil
}

// ReserveSpend atomically checks month-to-date spend against a ceiling and,
// when the request fits, inserts a PENDING ledger debit of estCost. The leading
// DELETE of stale reservations is a write, so it grabs SQLite's RESERVED lock
// before the SELECT — concurrent reservers serialize and each sees the others'
// pending debits, so N batch workers cannot over-grant the ceiling. Returns the
// reservation row id, whether it was granted, and the pre-reservation total.
// A crash between reserve and reconcile leaves an orphan that over-counts (the
// safe ceiling direction) until the 5-minute stale-reap removes it.
func (x *ScrapeExtras) ReserveSpend(ctx context.Context, monthStart time.Time, ceiling, estCost int, mode, agent, family string, now time.Time) (int64, bool, int, error) {
	tx, err := x.db.BeginTx(ctx, nil)
	if err != nil {
		return 0, false, 0, err
	}
	defer func() { _ = tx.Rollback() }()

	staleCutoff := now.Add(-5 * time.Minute).UTC().Format(time.RFC3339)
	if _, err := tx.ExecContext(ctx, `DELETE FROM credit_ledger WHERE cost_source = 'reserve' AND created_at < ?`, staleCutoff); err != nil {
		return 0, false, 0, err
	}

	var total int
	if err := tx.QueryRowContext(ctx, `SELECT COALESCE(SUM(cost),0) FROM credit_ledger WHERE created_at >= ?`,
		monthStart.UTC().Format(time.RFC3339)).Scan(&total); err != nil {
		return 0, false, 0, err
	}
	if ceiling > 0 && total+estCost > ceiling {
		if err := tx.Commit(); err != nil { // commit the stale-reap even when refusing
			return 0, false, total, err
		}
		return 0, false, total, nil
	}
	res, err := tx.ExecContext(ctx, `INSERT INTO credit_ledger (mode, agent, family, cost, cost_source, created_at)
        VALUES (?,?,?,?, 'reserve', ?)`, mode, nullStr(agent), nullStr(family), estCost, now.UTC().Format(time.RFC3339))
	if err != nil {
		return 0, false, total, err
	}
	id, _ := res.LastInsertId()
	if err := tx.Commit(); err != nil {
		return 0, false, total, err
	}
	return id, true, total, nil
}

// ReconcileReservation converts a pending reservation into its final state once
// the call returns: a billed call (cost > 0) updates the reserved row to the
// authoritative cost; an unbilled call (cost 0) deletes it. The scrape_jobs row
// is written in the same transaction so the job log and ledger stay consistent.
func (x *ScrapeExtras) ReconcileReservation(ctx context.Context, reservationID int64, r CallRecord) error {
	tx, err := x.db.BeginTx(ctx, nil)
	if err != nil {
		return err
	}
	defer func() { _ = tx.Rollback() }()
	if r.Cost > 0 {
		if _, err := tx.ExecContext(ctx, `UPDATE credit_ledger SET cost = ?, cost_source = ?, agent = ?, family = ? WHERE id = ?`,
			r.Cost, r.CostSource, nullStr(r.Agent), nullStr(r.Family), reservationID); err != nil {
			return err
		}
	} else {
		if _, err := tx.ExecContext(ctx, `DELETE FROM credit_ledger WHERE id = ?`, reservationID); err != nil {
			return err
		}
	}
	ts := r.At.UTC().Format(time.RFC3339)
	var rem any
	if r.RemainingCredits >= 0 {
		rem = r.RemainingCredits
	}
	_, err = tx.ExecContext(ctx, `INSERT INTO scrape_jobs
        (kind, target, mode, agent, http_status, cost, cost_source, remaining_credits, bytes, ok, error, created_at)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?)`,
		r.Kind, r.Target, r.Mode, nullStr(r.Agent), r.HTTPStatus, r.Cost, r.CostSource, rem, r.Bytes, boolInt(r.OK), nullStr(r.Err), ts)
	if err != nil {
		return err
	}
	return tx.Commit()
}

// CancelReservation removes a pending reservation that was never dispatched
// (e.g. lease acquisition timed out), so an abandoned attempt doesn't leak budget.
func (x *ScrapeExtras) CancelReservation(ctx context.Context, reservationID int64) error {
	if reservationID == 0 {
		return nil
	}
	_, err := x.db.ExecContext(ctx, `DELETE FROM credit_ledger WHERE id = ? AND cost_source = 'reserve'`, reservationID)
	return err
}

// ---- Usage snapshots (/info) -------------------------------------------

// UsageSnapshot mirrors the Scrape.do /info payload plus a capture timestamp.
type UsageSnapshot struct {
	IsActive            bool      `json:"is_active"`
	ConcurrentRequest   int       `json:"concurrent_request"`
	RemainingConcurrent int       `json:"remaining_concurrent"`
	MaxMonthly          int       `json:"max_monthly"`
	RemainingMonthly    int       `json:"remaining_monthly"`
	CapturedAt          time.Time `json:"captured_at"`
}

// SaveUsage stores a /info capture.
func (x *ScrapeExtras) SaveUsage(ctx context.Context, u UsageSnapshot) error {
	_, err := x.db.ExecContext(ctx, `INSERT INTO usage_snapshots
        (is_active, concurrent_request, remaining_concurrent, max_monthly, remaining_monthly, captured_at)
        VALUES (?,?,?,?,?,?)`,
		boolInt(u.IsActive), u.ConcurrentRequest, u.RemainingConcurrent, u.MaxMonthly, u.RemainingMonthly,
		u.CapturedAt.UTC().Format(time.RFC3339))
	return err
}

// LatestUsage returns the most recent /info capture, or (nil, nil) if none.
func (x *ScrapeExtras) LatestUsage(ctx context.Context) (*UsageSnapshot, error) {
	var u UsageSnapshot
	var active int
	var ts string
	err := x.db.QueryRowContext(ctx, `SELECT is_active, concurrent_request, remaining_concurrent, max_monthly, remaining_monthly, captured_at
        FROM usage_snapshots ORDER BY captured_at DESC LIMIT 1`).
		Scan(&active, &u.ConcurrentRequest, &u.RemainingConcurrent, &u.MaxMonthly, &u.RemainingMonthly, &ts)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, err
	}
	u.IsActive = active != 0
	u.CapturedAt, _ = time.Parse(time.RFC3339, ts)
	return &u, nil
}

// ---- SERP snapshots ----------------------------------------------------

// OrganicRow is one flattened organic SERP result.
type OrganicRow struct {
	Position int    `json:"position"`
	Title    string `json:"title,omitempty"`
	Link     string `json:"link,omitempty"`
	Domain   string `json:"domain,omitempty"`
	Snippet  string `json:"snippet,omitempty"`
}

// SnapshotMeta keys a SERP snapshot.
type SnapshotMeta struct {
	ParamHash    string
	Query        string
	Gl           string
	Hl           string
	GoogleDomain string
	Device       string
	FetchedAt    time.Time
	Raw          string
}

// SaveSnapshot persists a SERP snapshot plus its flattened organic rows.
func (x *ScrapeExtras) SaveSnapshot(ctx context.Context, m SnapshotMeta, organic []OrganicRow) error {
	tx, err := x.db.BeginTx(ctx, nil)
	if err != nil {
		return err
	}
	defer func() { _ = tx.Rollback() }()
	ts := m.FetchedAt.UTC().Format(time.RFC3339)
	res, err := tx.ExecContext(ctx, `INSERT INTO serp_snapshots
        (param_hash, query, gl, hl, google_domain, device, organic_count, raw, fetched_at)
        VALUES (?,?,?,?,?,?,?,?,?)`,
		m.ParamHash, m.Query, nullStr(m.Gl), nullStr(m.Hl), nullStr(m.GoogleDomain), nullStr(m.Device), len(organic), nullStr(m.Raw), ts)
	if err != nil {
		return err
	}
	snapID, _ := res.LastInsertId()
	for _, o := range organic {
		if _, err := tx.ExecContext(ctx, `INSERT INTO serp_organic
            (snapshot_id, param_hash, position, title, link, domain, snippet, fetched_at)
            VALUES (?,?,?,?,?,?,?,?)`,
			snapID, m.ParamHash, o.Position, nullStr(o.Title), nullStr(o.Link), nullStr(o.Domain), nullStr(o.Snippet), ts); err != nil {
			return err
		}
	}
	return tx.Commit()
}

// LatestSnapshotRaw returns the most recent stored raw SERP payload for a
// param_hash plus when it was fetched, for cache-first reuse. found is false
// when no snapshot exists.
func (x *ScrapeExtras) LatestSnapshotRaw(ctx context.Context, paramHash string) (raw string, fetchedAt time.Time, found bool, err error) {
	var rawNull sql.NullString
	var ts string
	e := x.db.QueryRowContext(ctx, `SELECT raw, fetched_at FROM serp_snapshots
        WHERE param_hash = ? ORDER BY fetched_at DESC, id DESC LIMIT 1`, paramHash).Scan(&rawNull, &ts)
	if e == sql.ErrNoRows {
		return "", time.Time{}, false, nil
	}
	if e != nil {
		return "", time.Time{}, false, e
	}
	fetchedAt, _ = time.Parse(time.RFC3339, ts)
	return rawNull.String, fetchedAt, true, nil
}

// SnapshotRef identifies a stored snapshot for diffing.
type SnapshotRef struct {
	ID        int64
	Query     string
	FetchedAt time.Time
}

// TwoLatestSnapshots returns the two most recent snapshots for a param_hash
// (current, previous). Either may be nil if fewer than two exist.
func (x *ScrapeExtras) TwoLatestSnapshots(ctx context.Context, paramHash string) (cur, prev *SnapshotRef, err error) {
	rows, err := x.db.QueryContext(ctx, `SELECT id, query, fetched_at FROM serp_snapshots
        WHERE param_hash = ? ORDER BY fetched_at DESC, id DESC LIMIT 2`, paramHash)
	if err != nil {
		return nil, nil, err
	}
	defer rows.Close()
	var refs []*SnapshotRef
	for rows.Next() {
		var r SnapshotRef
		var ts string
		if err := rows.Scan(&r.ID, &r.Query, &ts); err != nil {
			return nil, nil, err
		}
		r.FetchedAt, _ = time.Parse(time.RFC3339, ts)
		refs = append(refs, &r)
	}
	if len(refs) > 0 {
		cur = refs[0]
	}
	if len(refs) > 1 {
		prev = refs[1]
	}
	return cur, prev, rows.Err()
}

// OrganicForSnapshot returns the flattened organic rows for a snapshot id,
// keyed by domain for diffing (lowest/best position per domain wins).
func (x *ScrapeExtras) OrganicForSnapshot(ctx context.Context, snapshotID int64) ([]OrganicRow, error) {
	rows, err := x.db.QueryContext(ctx, `SELECT position, title, link, domain, snippet
        FROM serp_organic WHERE snapshot_id = ? ORDER BY position`, snapshotID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var out []OrganicRow
	for rows.Next() {
		var o OrganicRow
		var title, link, domain, snippet sql.NullString
		if err := rows.Scan(&o.Position, &title, &link, &domain, &snippet); err != nil {
			return nil, err
		}
		o.Title, o.Link, o.Domain, o.Snippet = title.String, link.String, domain.String, snippet.String
		out = append(out, o)
	}
	return out, rows.Err()
}

// TrackedHash is a distinct (param_hash, query) with at least two snapshots,
// used by `movers` to scan every tracked query.
type TrackedHash struct {
	ParamHash string
	Query     string
	Count     int
}

// TrackedHashes returns every param_hash that has >= 2 snapshots.
func (x *ScrapeExtras) TrackedHashes(ctx context.Context) ([]TrackedHash, error) {
	rows, err := x.db.QueryContext(ctx, `SELECT param_hash, MAX(query), COUNT(*) c
        FROM serp_snapshots GROUP BY param_hash HAVING c >= 2 ORDER BY MAX(fetched_at) DESC`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var out []TrackedHash
	for rows.Next() {
		var t TrackedHash
		if err := rows.Scan(&t.ParamHash, &t.Query, &t.Count); err != nil {
			return nil, err
		}
		out = append(out, t)
	}
	return out, rows.Err()
}

// ---- Cost budget -------------------------------------------------------

// Budget holds the configured spend ceilings (either may be unset).
type Budget struct {
	MaxCredits    sql.NullInt64
	MaxMonthlyPct sql.NullFloat64
	UpdatedAt     time.Time
}

// GetBudget returns the saved budget settings (zero-value if none saved).
func (x *ScrapeExtras) GetBudget(ctx context.Context) (Budget, error) {
	var b Budget
	var ts sql.NullString
	err := x.db.QueryRowContext(ctx, `SELECT max_credits, max_monthly_pct, updated_at FROM cost_budget WHERE id = 1`).
		Scan(&b.MaxCredits, &b.MaxMonthlyPct, &ts)
	if err == sql.ErrNoRows {
		return Budget{}, nil
	}
	if err != nil {
		return b, err
	}
	if ts.Valid {
		b.UpdatedAt, _ = time.Parse(time.RFC3339, ts.String)
	}
	return b, nil
}

// SetBudget upserts the budget ceilings. Nil pointers leave a field unchanged.
func (x *ScrapeExtras) SetBudget(ctx context.Context, maxCredits *int, maxMonthlyPct *float64, now time.Time) error {
	cur, err := x.GetBudget(ctx)
	if err != nil {
		return err
	}
	mc := cur.MaxCredits
	mp := cur.MaxMonthlyPct
	if maxCredits != nil {
		mc = sql.NullInt64{Int64: int64(*maxCredits), Valid: true}
	}
	if maxMonthlyPct != nil {
		mp = sql.NullFloat64{Float64: *maxMonthlyPct, Valid: true}
	}
	_, err = x.db.ExecContext(ctx, `INSERT INTO cost_budget (id, max_credits, max_monthly_pct, updated_at)
        VALUES (1, ?, ?, ?)
        ON CONFLICT(id) DO UPDATE SET max_credits=excluded.max_credits, max_monthly_pct=excluded.max_monthly_pct, updated_at=excluded.updated_at`,
		nullInt64(mc), nullFloat(mp), now.UTC().Format(time.RFC3339))
	return err
}

// ---- helpers -----------------------------------------------------------

func boolInt(b bool) int {
	if b {
		return 1
	}
	return 0
}

func nullStr(s string) any {
	if s == "" {
		return nil
	}
	return s
}

func nullInt64(v sql.NullInt64) any {
	if !v.Valid {
		return nil
	}
	return v.Int64
}

func nullFloat(v sql.NullFloat64) any {
	if !v.Valid {
		return nil
	}
	return v.Float64
}

func scanKV(ctx context.Context, db *sql.DB, query, arg string, dst map[string]int) error {
	rows, err := db.QueryContext(ctx, query, arg)
	if err != nil {
		return err
	}
	defer rows.Close()
	for rows.Next() {
		var k string
		var v int
		if err := rows.Scan(&k, &v); err != nil {
			return err
		}
		dst[k] = v
	}
	return rows.Err()
}
